import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { toast } from "sonner";
import { profileService, type UserProfile } from "@/api/auth/profileService";
import { authService } from "@/api/auth/authService";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { formatDistanceToNow } from "date-fns";
import { getApiErrorMessage } from "@/api/app/apiError";
import { uploadService } from "@/api/uploadService";
import { useAuth } from "@/shared/AuthContext";
import {
  Shield,
  MapPin,
  Key,
  Loader2,
  Eye,
  EyeOff,
  UserCircle,
  ChevronLeft,
  SmartphoneNfc,
  LogOut,
  Monitor,
  Globe,
  Smartphone,
  X,
} from "lucide-react";
import { Button } from "@/shadcn/components/ui/button";
import { Input } from "@/shadcn/components/ui/input";
import { Label } from "@/shadcn/components/ui/label";
import { Badge } from "@/shadcn/components/ui/badge";
import HarmonyForm from "@/components/forms/HarmonyForm";
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import { UserAvatar } from "@/components/ui/UserAvatar";
import { HarmonyProfilePictureUploader } from "@/components/ui/harmony-profile-picture-uploader";

function InfoRow({ label, value }: { label: string; value?: string | null }) {
  return (
    <div className="flex justify-between items-center py-2.5 border-b border-border/20 last:border-0">
      <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">{label}</span>
      <span className="text-sm font-semibold text-foreground">{value || "—"}</span>
    </div>
  );
}

function AddressBlock({ address }: { address: NonNullable<UserProfile["currentAddress"]> }) {
  const namePart = [address.firstName, address.lastName].filter(Boolean).join(" ");
  return (
    <div className="space-y-1 text-sm">
      {namePart && <p className="font-semibold text-foreground">{namePart}</p>}
      {address.addressLine && <p className="text-muted-foreground">{address.addressLine}</p>}
      {(address.city || address.state || address.zipCode) && (
        <p className="text-muted-foreground">
          {[address.city, address.state, address.zipCode].filter(Boolean).join(", ")}
        </p>
      )}
      {address.country && <p className="text-muted-foreground">{address.country}</p>}
    </div>
  );
}

function DeviceIcon({ name }: { name: string | null }) {
  const lower = name?.toLowerCase() ?? '';
  if (lower.includes('mobile') || lower.includes('android') || lower.includes('iphone'))
    return <Smartphone size={14} className="text-muted-foreground shrink-0 mt-0.5" />;
  if (lower.includes('mozilla') || lower.includes('chrome') || lower.includes('safari') || lower.includes('webkit'))
    return <Globe size={14} className="text-muted-foreground shrink-0 mt-0.5" />;
  return <Monitor size={14} className="text-muted-foreground shrink-0 mt-0.5" />;
}

interface UserDevice {
  id: string;
  deviceName?: string | null;
  ipAddress?: string | null;
  lastUsedAt: string;
}

function SessionsSection({ lastLoginAt, passwordLastChangedAt }: { lastLoginAt?: string | null; passwordLastChangedAt?: string | null }) {
  const { logout } = useAuth();
  const queryClient = useQueryClient();
  const devicesKey = ['my-devices'];

  const { data: devices = [], isLoading } = useQuery<UserDevice[]>({
    queryKey: devicesKey,
    queryFn: authService.getMyDevices,
    staleTime: 30_000,
  });

  const [revokingId, setRevokingId] = React.useState<string | null>(null);

  const revokeOneMutation = useMutation({
    mutationFn: (deviceId: string) => authService.revokeMyDevice(deviceId),
    onMutate: (id) => setRevokingId(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: devicesKey });
      toast.success('Session revoked.');
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to revoke session.')),
    onSettled: () => setRevokingId(null),
  });

  const revokeAllMutation = useMutation({
    mutationFn: authService.revokeAllMyDevices,
    onSuccess: () => {
      toast.success('All sessions revoked. Signing you out…');
      setTimeout(() => logout(), 1200);
    },
    onError: (err) => toast.error(getApiErrorMessage(err, 'Failed to revoke sessions.')),
  });

  const anyPending = revokeOneMutation.isPending || revokeAllMutation.isPending;

  return (
    <div className="bg-card rounded-xl border border-border shadow-sm overflow-hidden">
      <div className="px-6 py-4 border-b border-border flex items-center justify-between gap-2">
        <div className="flex items-center gap-2">
          <SmartphoneNfc size={16} className="text-primary" />
          <h3 className="text-sm font-semibold text-foreground">Security</h3>
        </div>
        {devices.length > 0 && (
          <Button
            variant="outline"
            size="sm"
            disabled={anyPending}
            onClick={() => revokeAllMutation.mutate()}
          >
            {revokeAllMutation.isPending
              ? <Loader2 size={13} className="animate-spin" />
              : <LogOut size={13} />
            }
            Sign out all sessions
          </Button>
        )}
      </div>
      <div className="p-6 space-y-4">
        {(lastLoginAt || passwordLastChangedAt) && (
          <div className="grid grid-cols-2 gap-4 pb-4 border-b border-border/40">
            <div>
              <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider mb-0.5">Last Login</p>
              <p className="text-sm font-medium text-foreground">
                {lastLoginAt ? formatDistanceToNow(new Date(lastLoginAt), { addSuffix: true }) : '—'}
              </p>
            </div>
            <div>
              <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider mb-0.5">Password Last Changed</p>
              <p className="text-sm font-medium text-foreground">
                {passwordLastChangedAt ? formatDistanceToNow(new Date(passwordLastChangedAt), { addSuffix: true }) : '—'}
              </p>
            </div>
          </div>
        )}
        {isLoading ? (
          <p className="text-sm text-muted-foreground">Loading sessions…</p>
        ) : devices.length === 0 ? (
          <p className="text-sm text-muted-foreground">No active sessions found.</p>
        ) : (
          <ul className="space-y-2">
            {devices.map((d) => (
              <li key={d.id} className="flex items-start gap-3 rounded-md border p-3">
                <DeviceIcon name={d.deviceName ?? null} />
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium truncate">{d.deviceName ?? 'Unknown device'}</p>
                  <div className="text-xs text-muted-foreground mt-0.5 space-y-0.5">
                    {d.ipAddress && <div>IP: {d.ipAddress}</div>}
                    <div>Last active: {formatDistanceToNow(new Date(d.lastUsedAt), { addSuffix: true })}</div>
                  </div>
                </div>
                <Button
                  size="icon-xs"
                  variant="ghost"
                  className="shrink-0 text-muted-foreground hover:text-destructive hover:bg-destructive/10"
                  disabled={anyPending}
                  onClick={() => revokeOneMutation.mutate(d.id)}
                  title="Sign out this session"
                >
                  {revokingId === d.id
                    ? <Loader2 size={12} className="animate-spin" />
                    : <X size={12} />
                  }
                </Button>
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
}

interface UserProfilePageProps {
  /** True when viewing own profile (/my-profile). False when admin views another user's profile (/users/:id). */
  isSelf?: boolean;
  /** User ID to load when isSelf=false. Ignored when isSelf=true. */
  userId?: string;
}

const UserProfilePage = ({ isSelf = false, userId: propUserId }: UserProfilePageProps) => {
  const params = useParams<{ userId: string }>();
  const navigate = useNavigate();
  const { profilePictureVersion, setProfilePictureVersion } = useAuth();

  const userId = isSelf ? undefined : (propUserId || params.userId);

  const [data, setData] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [photoUploading, setPhotoUploading] = useState(false);

  const [editOpen, setEditOpen] = useState(false);
  const [pwOpen, setPwOpen] = useState(false);

  const [pwData, setPwData] = useState({ oldPassword: "", newPassword: "", confirmPassword: "" });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [editError, setEditError] = useState("");
  const [pwError, setPwError] = useState("");

  const [showOld, setShowOld] = useState(false);
  const [showNew, setShowNew] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const fetchProfile = async () => {
    try {
      setLoading(true);
      const profile = isSelf
        ? await profileService.getMe()
        : await profileService.getById(userId!);
      setData(profile);
      if (isSelf) setProfilePictureVersion(profile.profilePictureVersion ?? null);
    } catch (err) {
      setError(getApiErrorMessage(err, "Failed to fetch profile."));
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect -- async fetch; setLoading(true) at entry is intentional
    fetchProfile();
  }, [userId, isSelf]); // eslint-disable-line react-hooks/exhaustive-deps

  const handlePhotoUpload = async (file: File) => {
    setPhotoUploading(true);
    try {
      await uploadService.upload("/account/upload-profile-picture", file);
      await fetchProfile();
      toast.success("Profile picture updated.");
    } catch (err) {
      toast.error(getApiErrorMessage(err, "Failed to update profile picture."));
    } finally {
      setPhotoUploading(false);
    }
  };

  const handlePhotoRemove = async () => {
    try {
      await profileService.deleteProfilePicture();
      setProfilePictureVersion(null);
      setData(prev => prev ? { ...prev, profilePictureUrl: null, profilePictureVersion: null } : prev);
      toast.success("Profile picture removed.");
    } catch (err) {
      toast.error(getApiErrorMessage(err, "Failed to remove profile picture."));
    }
  };

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleProfileUpdate = async (formData: any) => {
    setIsSubmitting(true);
    setEditError("");
    try {
      const mapAddress = (addr: Record<string, unknown>): import("@/types/dto").AddressDTO | undefined =>
        addr?.AddressLine
          ? {
              firstName:   String(addr.FirstName   ?? ""),
              lastName:    String(addr.LastName    ?? ""),
              addressLine: String(addr.AddressLine),
              city:        String(addr.City        ?? ""),
              state:       String(addr.State       ?? ""),
              zipCode:     String(addr.ZipCode     ?? ""),
              country:     String(addr.Country     ?? ""),
            }
          : undefined;

      const payload = {
        firstName:      formData.FirstName ?? "",
        middleName:     formData.MiddleName,
        lastName:       formData.LastName ?? "",
        phoneNumber:    formData.PhoneNumber,
        currentAddress: mapAddress(formData.CurrentAddress),
        timeZone:       formData.TimeZone,
      };

      if (isSelf) {
        await profileService.updateProfile(payload);
      } else {
        await profileService.updateProfileById(userId!, payload);
      }

      setData({
        ...data!,
        firstName:      formData.FirstName,
        middleName:     formData.MiddleName,
        lastName:       formData.LastName,
        phoneNumber:    formData.PhoneNumber,
        timeZone:       formData.TimeZone,
        fullName:       [formData.FirstName, formData.MiddleName, formData.LastName].filter(Boolean).join(" "),
        currentAddress: mapAddress(formData.CurrentAddress),
      });
      setEditOpen(false);
    } catch (err) {
      setEditError(getApiErrorMessage(err, "Update failed"));
    } finally {
      setIsSubmitting(false);
    }
  };

  const handlePasswordUpdate = async () => {
    if (pwData.newPassword.length < 16) {
      setPwError("Password must be at least 16 characters");
      return;
    }
    if (pwData.newPassword !== pwData.confirmPassword) {
      setPwError("Passwords do not match");
      return;
    }
    setPwError("");
    setIsSubmitting(true);
    try {
      await authService.changePassword({
        oldPassword: pwData.oldPassword,
        newPassword: pwData.newPassword,
      });
      setPwData({ oldPassword: "", newPassword: "", confirmPassword: "" });
      setPwOpen(false);
    } catch (err) {
      setPwError(getApiErrorMessage(err, "Update failed"));
    } finally {
      setIsSubmitting(false);
    }
  };

  if (loading)
    return (
      <div className="flex items-center justify-center min-h-100">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );

  if (error)
    return (
      <div className="max-w-md mx-auto mt-20 p-8 bg-card rounded-lg shadow border border-destructive/20">
        <h3 className="text-lg font-bold text-destructive mb-2">Error Loading Profile</h3>
        <p className="text-destructive/80 text-sm">{error}</p>
        <Button className="mt-6 w-full" onClick={() => fetchProfile()}>
          Retry
        </Button>
      </div>
    );

  if (!data) return null;

  const avatarCacheKey = isSelf ? profilePictureVersion : (data.profilePictureVersion ?? null);

  return (
    <div className="page-wrapper flex flex-col" style={{ gap: "var(--section-padding)" }}>

      {/* ── Page Header ─────────────────────────────────────────────────────── */}
      <div className="flex items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          {!isSelf && (
            <Button variant="ghost" size="icon" onClick={() => navigate("/users")} aria-label="Back to users">
              <ChevronLeft size={20} />
            </Button>
          )}
          <div className="size-12 flex items-center justify-center rounded-(--radius-lg) bg-primary/10 shrink-0">
            <UserCircle className="w-7 h-7 text-primary" />
          </div>
          <div>
            <h1 className="page-title">{isSelf ? "My Profile" : (data.fullName || "User Profile")}</h1>
            <p className="page-subtitle">{isSelf ? "View and manage your account information." : "View and manage this user's profile information."}</p>
          </div>
        </div>
        <div className="flex items-center gap-2 shrink-0">
          {isSelf && (
            <Button
              variant="outline"
              size="sm"
              onClick={() => { setPwError(""); setPwOpen(true); }}
            >
              <Key size={14} /> Change Password
            </Button>
          )}
          {!isSelf && userId && (
            <Button variant="outline" size="sm" onClick={() => navigate(`/work-schedule/${userId}`)}>
              View Schedule
            </Button>
          )}
          <Button size="sm" onClick={() => { setEditError(""); setEditOpen(true); }}>
            Edit Profile
          </Button>
        </div>
      </div>

      {/* ── Profile Overview card ─────────────────────────────────────────── */}
      <div className="bg-card rounded-xl border border-border shadow-sm p-6">
        <div className="flex flex-col sm:flex-row items-center gap-(--section-padding)">

          {/* Avatar with photo upload */}
          <HarmonyProfilePictureUploader
            imageUrl={null}
            onFileSelected={isSelf ? handlePhotoUpload : async () => {}}
            onRemove={isSelf && data.profilePictureUrl ? handlePhotoRemove : undefined}
            uploading={photoUploading}
            shape="rounded"
            size="lg"
            fallback={
              <UserAvatar
                userId={data.id}
                firstName={data.firstName}
                lastName={data.lastName}
                pictureSize="profile"
                cacheKey={avatarCacheKey}
                className="w-full h-full rounded-2xl"
                fallbackClassName="rounded-2xl text-4xl"
              />
            }
          />

          {/* Name + email */}
          <div className="min-w-0">
            <h2 className="text-xl font-bold text-foreground truncate">
              {data.fullName || "User Profile"}
            </h2>
            <p className="text-sm text-muted-foreground mt-0.5">{data.email}</p>
          </div>

          {/* Roles */}
          {data.roles && data.roles.length > 0 && (
            <>
              <div className="hidden sm:block w-px h-12 bg-border self-center shrink-0" />
              <div className="flex flex-col gap-1.5 shrink-0">
                <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider mb-0.5">Roles</p>
                {data.roles.map((role) => (
                  <Badge
                    key={role}
                    variant="outline"
                    className="bg-primary/10 text-primary border-primary/20 text-[10px] font-bold uppercase tracking-wider rounded-full justify-center"
                  >
                    {role}
                  </Badge>
                ))}
              </div>
              <div className="hidden sm:block w-px h-12 bg-border self-center shrink-0" />
            </>
          )}

          {/* Key identifiers */}
          <div className="flex flex-wrap gap-x-8 gap-y-3 shrink-0">
            {data.employeeID && (
              <div>
                <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">Employee ID</p>
                <p className="text-sm font-bold text-foreground">{data.employeeID}</p>
              </div>
            )}
            {data.joiningDate && (
              <div>
                <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">Joining Date</p>
                <p className="text-sm font-bold text-foreground">{data.joiningDate}</p>
              </div>
            )}
            {data.leavingDate && (
              <div>
                <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">Leaving Date</p>
                <p className="text-sm font-bold text-foreground">{data.leavingDate}</p>
              </div>
            )}
            {data.reasonForLeaving && (
              <div>
                <p className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">Reason</p>
                <p className="text-sm font-bold text-foreground">{data.reasonForLeaving}</p>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* ── 4-card details grid ───────────────────────────────────────────── */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6">

        {/* Personal Details */}
        <div className="bg-card rounded-xl border border-border shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-border flex items-center gap-2">
            <UserCircle size={16} className="text-primary" />
            <h3 className="text-sm font-semibold text-foreground">Personal Details</h3>
          </div>
          <div className="p-6">
            <InfoRow label="First Name" value={data.firstName} />
            <InfoRow label="Middle Name" value={data.middleName} />
            <InfoRow label="Last Name" value={data.lastName} />
            <InfoRow label="Email" value={data.email} />
            <InfoRow label="Phone" value={data.phoneNumber} />
            <InfoRow label="Time Zone" value={data.timeZone} />
          </div>
        </div>

        {/* System Identity */}
        <div className="bg-card rounded-xl border border-border shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-border flex items-center gap-2">
            <Shield size={16} className="text-primary" />
            <h3 className="text-sm font-semibold text-foreground">System Identity</h3>
          </div>
          <div className="p-6">
            <InfoRow label="Birth Date" value={data.birthDate} />
            <InfoRow label="PAN" value={data.pan} />
            <InfoRow label="Aadhaar" value={data.aadhar} />
            <InfoRow label="Status" value={data.active ? "Active" : "Inactive"} />
          </div>
        </div>

        {/* Current Address */}
        <div className="bg-card rounded-xl border border-border shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-border flex items-center gap-2">
            <MapPin size={16} className="text-primary" />
            <h3 className="text-sm font-semibold text-foreground">Current Address</h3>
          </div>
          <div className="p-6">
            {data.currentAddress ? (
              <AddressBlock address={data.currentAddress} />
            ) : (
              <p className="text-sm text-muted-foreground italic">Not set</p>
            )}
          </div>
        </div>

        {/* Permanent Address */}
        <div className="bg-card rounded-xl border border-border shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-border flex items-center gap-2">
            <MapPin size={16} className="text-primary" />
            <h3 className="text-sm font-semibold text-foreground">Permanent Address</h3>
          </div>
          <div className="p-6">
            {data.permanentAddress ? (
              <AddressBlock address={data.permanentAddress} />
            ) : (
              <p className="text-sm text-muted-foreground italic">Not set</p>
            )}
          </div>
        </div>
      </div>

      {/* ── Security & Sessions (self only) ─────────────────────────────────── */}
      {isSelf && (
        <SessionsSection
          lastLoginAt={data.lastLoginAt}
          passwordLastChangedAt={data.passwordLastChangedAt}
        />
      )}

      {/* ── Edit Profile dialog ──────────────────────────────────────────────── */}
      <HarmonyDialog
        open={editOpen}
        onOpenChange={setEditOpen}
        title="Edit Profile"
        description="Update personal information."
        size="xl"
        formId="edit-profile-form"
        submitLabel="Save Changes"
        isSubmitting={isSubmitting}
      >
        {editError && (
          <p className="text-sm text-destructive mb-4">{editError}</p>
        )}
        <HarmonyForm
          id="edit-profile-form"
          dtoName="UpdateProfileDTO"
          mode="edit"
          initialValues={{
            FirstName:   data.firstName,
            MiddleName:  data.middleName,
            LastName:    data.lastName,
            PhoneNumber: data.phoneNumber,
            TimeZone:    data.timeZone,
            CurrentAddress: data.currentAddress
              ? {
                  FirstName:   data.currentAddress.firstName,
                  LastName:    data.currentAddress.lastName,
                  AddressLine: data.currentAddress.addressLine,
                  City:        data.currentAddress.city,
                  State:       data.currentAddress.state,
                  ZipCode:     data.currentAddress.zipCode,
                  Country:     data.currentAddress.country,
                }
              : null,
          }}
          onSubmit={handleProfileUpdate}
          hideSubmitButton
          isPending={isSubmitting}
        />
      </HarmonyDialog>

      {/* ── Change Password dialog (self only) ───────────────────────────────── */}
      {isSelf && (
        <HarmonyDialog
          open={pwOpen}
          onOpenChange={(open) => {
            if (isSubmitting) return;
            if (!open) {
              setPwData({ oldPassword: "", newPassword: "", confirmPassword: "" });
              setPwError("");
              setShowOld(false);
              setShowNew(false);
              setShowConfirm(false);
            }
            setPwOpen(open);
          }}
          title="Change Password"
          description="Your password must be at least 16 characters."
          size="md"
          onSubmit={handlePasswordUpdate}
          submitLabel="Update Password"
          isSubmitting={isSubmitting}
        >
          <div className="space-y-4">
            {[
              { label: "Current Password",  key: "oldPassword"     as const, show: showOld,     toggle: () => setShowOld(s => !s) },
              { label: "New Password",      key: "newPassword"     as const, show: showNew,     toggle: () => setShowNew(s => !s),     placeholder: "Min. 16 characters" },
              { label: "Confirm Password",  key: "confirmPassword" as const, show: showConfirm, toggle: () => setShowConfirm(s => !s), placeholder: "Repeat new password" },
            ].map(({ label, key, show, toggle, placeholder }) => (
              <div key={key} className="space-y-1.5">
                <Label>{label}</Label>
                <div className="relative">
                  <Input
                    type={show ? "text" : "password"}
                    value={pwData[key]}
                    onChange={(e) => setPwData(prev => ({ ...prev, [key]: e.target.value }))}
                    placeholder={placeholder ?? "Enter password"}
                    className="pr-10"
                  />
                  <button
                    type="button"
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                    onClick={toggle}
                  >
                    {show ? <EyeOff size={16} /> : <Eye size={16} />}
                  </button>
                </div>
              </div>
            ))}
            {pwError && <p className="text-sm text-destructive">{pwError}</p>}
          </div>
        </HarmonyDialog>
      )}

    </div>
  );
};

export default UserProfilePage;
